
'use client';

import React, { useMemo } from 'react';
import { 
  Users, 
  MessageSquare, 
  Star,
  Database,
  Terminal,
  Cpu,
  HardDrive,
  Loader2
} from 'lucide-react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { useCollection, useFirestore, useMemoFirebase, useUser } from '@/firebase';
import { collection, collectionGroup } from 'firebase/firestore';
import { 
  PieChart, 
  Pie, 
  Cell, 
  ResponsiveContainer, 
  Tooltip as RechartsTooltip 
} from 'recharts';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { format } from 'date-fns';
import { cn } from '@/lib/utils';

export default function AdminDashboardPage() {
  const firestore = useFirestore();
  const { user, isUserLoading } = useUser();

  // Fetch all users to count registered accounts
  const usersQuery = useMemoFirebase(() => {
    if (!firestore || isUserLoading || !user) return null;
    return collection(firestore, 'users');
  }, [firestore, user, isUserLoading]);
  const { data: users, isLoading: isUsersLoading } = useCollection(usersQuery);

  // Fetch all feedback docs via Collection Group
  const feedbackQuery = useMemoFirebase(() => {
    if (!firestore || isUserLoading || !user) return null;
    return collectionGroup(firestore, 'feedback');
  }, [firestore, user, isUserLoading]);
  const { data: allFeedback, isLoading: isFeedbackLoading } = useCollection(feedbackQuery);

  // Filter users to only include those with completed registration (valid email)
  const registeredUsers = useMemo(() => {
    if (!users) return [];
    return users.filter(u => u.email && u.email.includes('@'));
  }, [users]);

  // Metrics calculations
  const totalUsers = registeredUsers.length;
  const totalFeedbacks = allFeedback?.length || 0;
  
  const avgRating = useMemo(() => {
    if (!allFeedback || allFeedback.length === 0) return "0.0";
    const sum = allFeedback.reduce((acc, f) => acc + (Number(f.rating) || 0), 0);
    return (sum / allFeedback.length).toFixed(1);
  }, [allFeedback]);

  const countryData = useMemo(() => {
    if (!registeredUsers) return [];
    const counts: Record<string, number> = {};
    registeredUsers.forEach(u => {
      const c = u.country || 'Global';
      counts[c] = (counts[c] || 0) + 1;
    });
    return Object.entries(counts).map(([name, value]) => ({ name, value }));
  }, [registeredUsers]);

  const COLORS = ['#1e3a8a', '#064e3b', '#10b981', '#00A3AD', '#8b5cf6', '#f59e0b'];

  if (isUserLoading || isUsersLoading || isFeedbackLoading) {
    return (
      <div className="flex h-[40vh] items-center justify-center">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      {/* Summary Row */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <SummaryItem icon={Users} label="Total Users" value={totalUsers} />
        <SummaryItem icon={MessageSquare} label="Total Feedbacks" value={totalFeedbacks} />
        <SummaryItem icon={Star} label="Avg Rating" value={`${avgRating} ★`} />
      </div>

      {/* Analytics Row */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <Card className="shadow-xl border-0 rounded-[2rem] overflow-hidden bg-white">
          <CardHeader className="py-6 px-8 border-b border-slate-50 bg-slate-50/30">
            <CardTitle className="text-xs font-black uppercase tracking-[0.2em] text-slate-400 flex items-center gap-2">
              <Database className="w-4 h-4 text-primary" /> User Demographics
            </CardTitle>
          </CardHeader>
          <CardContent className="h-[350px] flex items-center justify-center p-8">
            {countryData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={countryData}
                    innerRadius={0}
                    outerRadius={120}
                    paddingAngle={0}
                    dataKey="value"
                    stroke="#fff"
                    strokeWidth={4}
                  >
                    {countryData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                    ))}
                  </Pie>
                  <RechartsTooltip 
                    contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)' }}
                  />
                </PieChart>
              </ResponsiveContainer>
            ) : (
              <div className="text-[10px] font-bold text-slate-300 uppercase tracking-widest">No Demographic Data</div>
            )}
          </CardContent>
        </Card>

        <Card className="shadow-xl border-0 rounded-[2rem] overflow-hidden bg-white">
          <CardHeader className="py-6 px-8 border-b border-slate-50 bg-slate-50/30">
            <CardTitle className="text-xs font-black uppercase tracking-[0.2em] text-slate-400 flex items-center gap-2">
              <MessageSquare className="w-4 h-4 text-primary" /> Feedback Distribution
            </CardTitle>
          </CardHeader>
          <CardContent className="h-[350px] flex items-center justify-center p-8">
            {allFeedback && allFeedback.length > 0 ? (
              <div className="w-full space-y-6">
                {[5, 4, 3, 2, 1].map(r => {
                  const count = allFeedback.filter(f => Number(f.rating) === r).length;
                  const percent = (count / allFeedback.length) * 100;
                  return (
                    <div key={r} className="flex items-center gap-4">
                      <span className="text-xs font-black text-slate-600 w-8">{r} ★</span>
                      <div className="flex-1 h-3 bg-slate-100 rounded-full overflow-hidden shadow-inner">
                        <div 
                          className="h-full bg-gradient-to-r from-primary to-accent transition-all duration-1000" 
                          style={{ width: `${percent}%` }} 
                        />
                      </div>
                      <span className="text-xs font-bold text-muted-foreground w-10 text-right">{count}</span>
                    </div>
                  );
                })}
              </div>
            ) : (
              <span className="text-xs font-bold text-slate-300 uppercase tracking-widest">No Feedback Recorded</span>
            )}
          </CardContent>
        </Card>
      </div>

      {/* System Information */}
      <div className="space-y-6">
        <h3 className="text-xs font-black uppercase tracking-[0.3em] text-slate-400 flex items-center gap-3 px-2">
          <Terminal className="w-4 h-4 text-primary" /> System Architecture
        </h3>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
          <SystemInfoCard icon={Database} label="Service Status" value="Firestore Cloud" badge="Connected" />
          <SystemInfoCard icon={Cpu} label="App Engine" value="Next.js 15.5" />
          <SystemInfoCard icon={HardDrive} label="Auth Engine" value="Firebase Auth" />
          <SystemInfoCard icon={HardDrive} label="Database Region" value="Global-Edge" />
        </div>
      </div>

      {/* Tables Row */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <Card className="shadow-xl border-0 rounded-[2rem] overflow-hidden bg-white">
          <CardHeader className="py-6 px-8 border-b border-slate-50 flex flex-row items-center justify-between">
            <CardTitle className="text-xs font-black uppercase tracking-[0.2em] text-slate-400 flex items-center gap-2">
              <Users className="w-4 h-4 text-primary" /> Newest Users
            </CardTitle>
            <Button variant="ghost" size="sm" className="h-8 rounded-xl text-[10px] font-black uppercase tracking-wider text-primary hover:bg-primary/5">Explore All</Button>
          </CardHeader>
          <CardContent className="p-0">
            <Table>
              <TableHeader className="bg-slate-50/50">
                <TableRow className="border-0">
                  <TableHead className="text-[10px] font-black h-12 uppercase tracking-widest pl-8">Identity</TableHead>
                  <TableHead className="text-[10px] font-black h-12 uppercase tracking-widest">Region</TableHead>
                  <TableHead className="text-[10px] font-black h-12 uppercase tracking-widest text-right pr-8">Status</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {registeredUsers.slice(0, 5).map(u => (
                  <TableRow key={u.id} className="hover:bg-slate-50/50 transition-colors border-slate-50">
                    <TableCell className="py-4 pl-8">
                      <div className="flex flex-col">
                        <span className="text-sm font-bold text-slate-700">{u.name}</span>
                        <span className="text-[10px] text-muted-foreground">{u.email}</span>
                      </div>
                    </TableCell>
                    <TableCell className="py-4">
                      <Badge variant="secondary" className="rounded-lg bg-slate-100 text-slate-600 font-bold border-0 text-[10px]">{u.country || 'Global'}</Badge>
                    </TableCell>
                    <TableCell className="text-right pr-8 py-4">
                      <Badge className="bg-emerald-500/10 text-emerald-600 border-0 rounded-lg text-[9px] font-black uppercase">Active</Badge>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </CardContent>
        </Card>

        <Card className="shadow-xl border-0 rounded-[2rem] overflow-hidden bg-white">
          <CardHeader className="py-6 px-8 border-b border-slate-50 flex flex-row items-center justify-between">
            <CardTitle className="text-xs font-black uppercase tracking-[0.2em] text-slate-400 flex items-center gap-2">
              <MessageSquare className="w-4 h-4 text-primary" /> Recent Testimonials
            </CardTitle>
            <Button variant="ghost" size="sm" className="h-8 rounded-xl text-[10px] font-black uppercase tracking-wider text-primary hover:bg-primary/5">Moderate</Button>
          </CardHeader>
          <CardContent className="p-0">
            <Table>
              <TableHeader className="bg-slate-50/50">
                <TableRow className="border-0">
                  <TableHead className="text-[10px] font-black h-12 uppercase tracking-widest pl-8">User</TableHead>
                  <TableHead className="text-[10px] font-black h-12 uppercase tracking-widest">Rating</TableHead>
                  <TableHead className="text-[10px] font-black h-12 uppercase tracking-widest text-right pr-8">Status</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {allFeedback?.slice(0, 5).map(f => (
                  <TableRow key={f.id} className="hover:bg-slate-50/50 transition-colors border-slate-50">
                    <TableCell className="py-4 pl-8">
                      <span className="text-sm font-bold text-slate-700">Verified User</span>
                    </TableCell>
                    <TableCell className="py-4">
                      <div className="flex gap-0.5">
                        {[...Array(5)].map((_, i) => (
                          <Star key={i} className={cn("w-3 h-3", i < (Number(f.rating) || 0) ? "fill-yellow-400 text-yellow-400" : "text-slate-200")} />
                        ))}
                      </div>
                    </TableCell>
                    <TableCell className="text-right pr-8 py-4">
                      <Badge className="bg-emerald-500/10 text-emerald-600 border-0 rounded-lg text-[9px] font-black">VERIFIED</Badge>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

function SummaryItem({ icon: Icon, label, value }: { icon: any, label: string, value: string | number }) {
  return (
    <Card className="shadow-xl border-0 border-l-[6px] border-l-primary rounded-2xl bg-white transition-all hover:scale-[1.02] active:scale-[0.98] group">
      <CardContent className="p-10 flex flex-col items-center justify-center space-y-4">
        <div className="p-4 rounded-[1.5rem] bg-slate-50 text-primary group-hover:bg-primary group-hover:text-white transition-colors duration-500 shadow-inner">
          <Icon className="w-10 h-10" />
        </div>
        <div className="text-center space-y-1">
          <div className="text-5xl font-black text-[#1e293b] tracking-tighter">{value}</div>
          <p className="text-[11px] font-black text-slate-400 uppercase tracking-[0.3em]">{label}</p>
        </div>
      </CardContent>
    </Card>
  );
}

function SystemInfoCard({ icon: Icon, label, value, badge }: { icon: any, label: string, value: string, badge?: string }) {
  return (
    <Card className="shadow-lg border-0 bg-white hover:shadow-2xl transition-all duration-500 rounded-[1.5rem]">
      <CardContent className="p-8 flex flex-col items-center justify-center space-y-4">
        <div className="w-12 h-12 rounded-2xl bg-slate-50 flex items-center justify-center text-primary shadow-inner">
          <Icon className="w-6 h-6" />
        </div>
        <div className="text-center space-y-2">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{label}</p>
          <div className="text-sm font-black text-[#1e293b]">{value}</div>
          {badge && <Badge className="h-5 px-3 text-[9px] font-black bg-emerald-500 hover:bg-emerald-600 border-0 rounded-full shadow-lg shadow-emerald-100">{badge}</Badge>}
        </div>
      </CardContent>
    </Card>
  );
}
